### Inject Source Map Metadata

Source: https://github.com/posthog/posthog.com/blob/master/contents/docs/error-tracking/upload-source-maps/web.mdx

This snippet shows how to inject source map metadata into your application's build output. This is a critical step to associate your minified JavaScript files with their corresponding source maps, enabling PostHog to reconstruct original code for debugging. The exact implementation may vary based on your build tool and setup.

```bash
# Example for Vite (add to vite.config.js)

import { defineConfig } from 'vite';

export default defineConfig({
  build: {
    sourcemap: true,
    rollupOptions: {
      output: {
        // Example of injecting a chunk ID, actual logic might differ
        manualChunks(id) {
          if (id.includes('node_modules')) {
            return 'vendor';
          }
        },
        assetFileNames: '[name].[hash].[ext]',
        chunkFileNames: '[name].[hash].js',
        entryFileNames: '[name].[hash].js',
      }
    }
  }
});

# Example for webpack (add to webpack.config.js)

module.exports = {
  // ... other webpack configurations
  devtool: 'source-map',
  output: {
    filename: '[name].[contenthash].js',
    chunkFilename: '[name].[contenthash].js',
  },
};

# Example for Rollup (add to rollup.config.js)

export default {
  // ... other Rollup configurations
  output: {
    sourcemap: true,
    file: 'dist/bundle.js',
    format: 'esm',
    // Example of naming conventions
    chunkFileNames: '[name]-[hash].js',
    entryFileNames: '[name]-[hash].js',
  },
};

```

