  "projects": {
    "my-app": {
      "architect": {
        "build": {
          "builder": "@angular-devkit/build-angular:application",
          "options": {
            "sourceMap": {
              "scripts": true, 
              "styles": true, 
              "hidden": true, 
              "vendor": true 
            }
          }
        }
      }
    }
  }
}
```

